noncompliant:
[DebuggerDisplay("Name = {FullName}")]
public class Person
{
    public string FirstName { get; set; }
    public string LastName { get; set; }
    // FullName doesn't exist - will cause CS0103 error in debugger
}

[DebuggerDisplay("Count: {Cnt}, Items: {ItemList}")]
public class Container
{
    public int Count { get; set; }
    public List<string> Items { get; set; }
    // Cnt and ItemList don't exist
}

[DebuggerDisplay("{GetDisplayName()}")]
public class Product
{
    public string Name { get; set; }
    // GetDisplayName() method doesn't exist
}

compliant:
[DebuggerDisplay("Name = {FirstName} {LastName}")]
public class Person
{
    public string FirstName { get; set; }
    public string LastName { get; set; }
}

[DebuggerDisplay("Count: {Count}, Items: {Items.Count}")]
public class Container
{
    public int Count { get; set; }
    public List<string> Items { get; set; }
}

[DebuggerDisplay("{Name} - {GetPrice()}")]
public class Product
{
    public string Name { get; set; }
    private string GetPrice() => "$10.00";
}
